import{_ as s,k as e,ac as n,j as t}from"./chunks/framework.eWqQbyyN.js";const h=JSON.parse('{"title":"UML Class Diagram","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"docs/class.md","filePath":"docs/class.md"}'),i={name:"docs/class.md"};function p(o,a,l,c,d,r){return t(),e("div",null,a[0]||(a[0]=[n(`<h1 id="uml-class-diagram" tabindex="-1">UML Class Diagram <a class="header-anchor" href="#uml-class-diagram" aria-label="Permalink to &quot;UML Class Diagram&quot;">​</a></h1><p>To create a UML class diagram, one uses the <code>classDiagram</code> diagram function:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>classDiagram {</span></span>
<span class="line"><span>    // define elements</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="elements" tabindex="-1">Elements <a class="header-anchor" href="#elements" aria-label="Permalink to &quot;Elements&quot;">​</a></h2><p>The following elements are supported:</p><h3 id="class" tabindex="-1"><code>class</code> <a class="header-anchor" href="#class" aria-label="Permalink to &quot;\`class\`&quot;">​</a></h3><p>Creats a new class element, with the defined name, and optional properties and operations:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>class(&quot;Hello world&quot;) {</span></span>
<span class="line"><span>    public {</span></span>
<span class="line"><span>        x : Int</span></span>
<span class="line"><span>        test : String</span></span>
<span class="line"><span>        print(value : String) : void</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Note that properties and functions are defined declaratively, and are not executable code. Thus, e.g. if <code>x</code> is a defined variable, the property is still named <code>x</code>, not the value of <code>x</code>. Five different types of visibility are supported:</p><ul><li><code>public</code></li><li><code>private</code></li><li><code>protected</code></li><li><code>package</code></li><li><code>default</code> (no visibility)</li></ul><p>Using the <code>section</code> function, one can also add another section to the body of the class</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>class(&quot;Test&quot;) {</span></span>
<span class="line"><span>    section(</span></span>
<span class="line"><span>        &quot;A new string entry&quot;,</span></span>
<span class="line"><span>        &quot;The next string entry&quot;</span></span>
<span class="line"><span>    )</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>To mark a class as abstract, one can use the <code>abstract</code> named argument:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>class(&quot;Test&quot;, abstract = true) {</span></span>
<span class="line"><span>    // ...</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Last, the <code>keywords</code> named argument can be used to add keywords or stereotypes in guillemets (<code>«</code> and <code>»</code>):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>class(&quot;TestEnum&quot;, keywords = list(&quot;enumeration&quot;)) {</span></span>
<span class="line"><span>    public {</span></span>
<span class="line"><span>        A</span></span>
<span class="line"><span>        B</span></span>
<span class="line"><span>        C</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>To simplify using classes later in the diagram, <code>class</code> automatically sets itself on the current scope if the variable is not yet defined:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>class(&quot;Test&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// is equivalent to</span></span>
<span class="line"><span>Test = class(&quot;Test&quot;)</span></span></code></pre></div><h3 id="interface" tabindex="-1"><code>interface</code> <a class="header-anchor" href="#interface" aria-label="Permalink to &quot;\`interface\`&quot;">​</a></h3><p>Creates a new interface element. Identical to <code>class</code>, however automatically adds the <code>«interface»</code> keyword.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>interface(&quot;Test&quot;) {</span></span>
<span class="line"><span>    // ...</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// is equivalent to</span></span>
<span class="line"><span>class(&quot;Test&quot;, keywords = list(&quot;interface&quot;)) {</span></span>
<span class="line"><span>    // ...</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="package" tabindex="-1"><code>package</code> <a class="header-anchor" href="#package" aria-label="Permalink to &quot;\`package\`&quot;">​</a></h3><p>Creates a UML package with a name</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>package(&quot;Test&quot;)</span></span></code></pre></div><p>Optionally, a function can be passed as second parameter, while this function is executed, it has no additional semantics:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>package(&quot;Test&quot;) {</span></span>
<span class="line"><span>    class(&quot;TestClass&quot;)</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// is equivalent to</span></span>
<span class="line"><span>package(&quot;Test)</span></span>
<span class="line"><span>class(&quot;TestClass&quot;)</span></span></code></pre></div><h3 id="comment" tabindex="-1"><code>comment</code> <a class="header-anchor" href="#comment" aria-label="Permalink to &quot;\`comment\`&quot;">​</a></h3><p>Allows creating UML comments:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>comment(&quot;This is a comment&quot;)</span></span></code></pre></div><h2 id="connections-associations" tabindex="-1">Connections / Associations <a class="header-anchor" href="#connections-associations" aria-label="Permalink to &quot;Connections / Associations&quot;">​</a></h2><p>Connections / Associations are created using a PlantUMl-inspired operator syntax. Both sides of the operand can be either points, or canvasElemments, and thus classes, interfaces, packages or comments. The following operators are supported:</p><ul><li><code>--</code> for a simple association</li><li><code>--*</code> for a composition</li><li><code>--&lt;&gt;</code> for an aggregation</li><li><code>extends</code> for a generalization</li><li><code>implements</code> for an implementation</li><li><code>..&gt;</code> for a dependency</li><li><code>--!</code> for an association not-navigatable in one direction</li><li><code>--&gt;</code> for an association navigatable in one direction</li><li>... and several combinations of the above, e.g, <code>!--!</code>, <code>*--&gt;</code>, ...</li></ul>`,32)]))}const g=s(i,[["render",p]]);export{h as __pageData,g as default};
